const toStr = (v) => String(v ?? '').trim();
const toNum = (v) => { const n = Number(v); return Number.isFinite(n) ? n : null; };
const encodePath = (p) => toStr(p).split('/').map(encodeURIComponent).join('/');

const getEnv = (key) => {
  try {
    if ($env && $env[key]) return String($env[key]).trim();
  } catch (_e) {}
  try {
    const p = (typeof globalThis !== 'undefined' && globalThis.process && globalThis.process.env)
      ? globalThis.process.env[key]
      : '';
    if (p) return String(p).trim();
  } catch (_e) {}
  return '';
};

const reqFromNormalize = (() => {
  try {
    return $items('Normalize Chat Input', 0, 0)[0]?.json || {};
  } catch (_e) {
    return {};
  }
})();

const req = {
  ...($json || {}),
  ...reqFromNormalize,
};

const question = toStr(req.question || '');
const owner = toStr(req.owner || getEnv('GITHUB_OWNER') || 'oliversoft-tech');
const token = toStr(req.github_token || getEnv('GITHUB_TOKEN') || '');
if (!token) {
  throw new Error('[Fetch PR + Code Context] GITHUB_TOKEN ausente. Defina em env (GITHUB_TOKEN) ou no Normalize Chat Input.');
}

const rows = $input.all().map((i) => i.json || {});
let repos = rows
  .map((r) => toStr(r.repo_name || r.name || r.repository || r.slug || ''))
  .filter(Boolean)
  .filter((n) => n.includes('fastroute-'));
if (repos.length === 0) repos = ['fastroute-domain', 'fastroute-api', 'fastroute-mobile-hybrid', 'fastroute-changemanagement'];
repos = [...new Set(repos)];

const gh = async (url) => this.helpers.httpRequest({
  method: 'GET',
  url,
  headers: {
    Authorization: 'Bearer ' + token,
    Accept: 'application/vnd.github+json',
    'X-GitHub-Api-Version': '2022-11-28'
  },
  json: true
});

const queryTerms = question
  .toLowerCase()
  .replace(/[^a-z0-9\s]/g, ' ')
  .split(/\s+/)
  .filter((t) => t.length >= 4)
  .slice(0, 10);

const allPrs = [];
for (const repo of repos) {
  const list = await gh('https://api.github.com/repos/' + owner + '/' + repo + '/pulls?state=all&sort=updated&direction=desc&per_page=100');
  for (const pr of (Array.isArray(list) ? list : [])) {
    const title = toStr(pr.title);
    const headRef = toStr(pr.head?.ref || '');
    const governanceLike = title.toLowerCase().includes('governance: impact analysis') || headRef.startsWith('codex/governance-');
    if (!governanceLike) continue;

    allPrs.push({
      repo,
      number: pr.number,
      title,
      state: pr.state,
      draft: !!pr.draft,
      created_at: pr.created_at,
      updated_at: pr.updated_at,
      merged_at: pr.merged_at,
      user: toStr(pr.user?.login || ''),
      url: toStr(pr.html_url || ''),
      body: toStr(pr.body || '').slice(0, 7000),
      head: toStr(pr.head?.ref || ''),
      base: toStr(pr.base?.ref || '')
    });
  }
}

allPrs.sort((a, b) => new Date(b.updated_at).getTime() - new Date(a.updated_at).getTime());
const selected = allPrs.slice(0, 25);

const fileIndex = [];
const commitHits = [];
for (const pr of selected) {
  try {
    const files = await gh('https://api.github.com/repos/' + owner + '/' + pr.repo + '/pulls/' + pr.number + '/files?per_page=100');
    pr.files = (Array.isArray(files) ? files : []).map((f) => ({
      filename: toStr(f.filename),
      status: toStr(f.status),
      additions: toNum(f.additions) || 0,
      deletions: toNum(f.deletions) || 0,
      raw_url: toStr(f.raw_url || ''),
      blob_url: toStr(f.blob_url || '')
    }));

    for (const f of pr.files) {
      fileIndex.push({
        repo: pr.repo,
        pr_number: pr.number,
        filename: f.filename,
        raw_url: f.raw_url,
        blob_url: f.blob_url,
        pr_url: pr.url,
      });
    }
  } catch (_e) {
    pr.files = [];
  }

  try {
    const commits = await gh('https://api.github.com/repos/' + owner + '/' + pr.repo + '/pulls/' + pr.number + '/commits?per_page=100');
    pr.commits = (Array.isArray(commits) ? commits : []).map((c) => {
      const msg = toStr(c?.commit?.message || '');
      return {
        sha: toStr(c?.sha || '').slice(0, 10),
        message: msg.slice(0, 900),
        author: toStr(c?.commit?.author?.name || c?.author?.login || ''),
      };
    });

    if (queryTerms.length > 0) {
      const text = pr.commits.map((c) => c.message).join(' \n ').toLowerCase();
      const matched = queryTerms.filter((t) => text.includes(t));
      if (matched.length > 0) {
        commitHits.push({
          repo: pr.repo,
          pr_number: pr.number,
          url: pr.url,
          matched_terms: [...new Set(matched)],
          commit_messages: pr.commits.map((c) => c.message).slice(0, 10),
        });
      }
    }
  } catch (_e) {
    pr.commits = [];
  }
}

const matches = fileIndex.filter((f) => {
  if (queryTerms.length === 0) return false;
  const hay = (f.filename + ' ' + f.blob_url).toLowerCase();
  return queryTerms.some((t) => hay.includes(t));
}).slice(0, 20);

const codeSnippets = [];
for (const m of matches) {
  try {
    const content = await gh('https://api.github.com/repos/' + owner + '/' + m.repo + '/contents/' + encodePath(m.filename) + '?ref=main');
    let decoded = '';
    if (content && content.content) {
      decoded = Buffer.from(String(content.content).replace(/\n/g, ''), 'base64').toString('utf8');
    }
    codeSnippets.push({
      repo: m.repo,
      pr_number: m.pr_number,
      filename: m.filename,
      pr_url: m.pr_url,
      code: toStr(decoded).slice(0, 2500)
    });
  } catch (_e) {
    // ignore fetch errors
  }
}

const fastrouteModeloDados = {
  fonte: 'skill:fastroute/references/modelo-dados.md',
  tabelas_chave: [
    'orders', 'addresses', 'routes', 'route_waypoints', 'waypoint_delivery_photo',
    'change_log', 'mutations_applied', 'users', 'clients', 'orders_import'
  ],
  relacionamentos_relevantes: [
    'addresses.order_id -> orders.id',
    'routes.import_id -> orders_import.id',
    'routes.driver_id -> users.id',
    'orders.import_id -> orders_import.id'
  ],
  pontos_atencao: [
    'route_waypoints e routes usam status/version para ciclo de entrega',
    'change_log e mutations_applied suportam trilha e idempotencia offline-first',
    'dados de latitude/longitude aparecem em ordens e enderecos e impactam clustering/roteirizacao',
    'fotos de comprovacao em waypoint_delivery_photo vinculam rota, waypoint e usuario'
  ]
};

return [{
  json: {
    route: req.route,
    session_id: req.session_id || 'default',
    chat_history: Array.isArray(req.chat_history) ? req.chat_history : [],
    question,
    owner,
    impact_workflow_id: req.impact_workflow_id,
    pr_context: {
      owner,
      repos,
      total_found: allPrs.length,
      selected_count: selected.length,
      query_terms: queryTerms,
      prs: selected,
      commit_text_hits: commitHits,
      code_snippets: codeSnippets,
      fastroute_modelo_dados: fastrouteModeloDados
    }
  }
}];

messageValues.message:
Voce e um arquiteto de mudancas e deve propor uma correcao a partir de PRs/codigo/commits existentes.
Considere tambem o modelo de dados do FastRoute presente no contexto.

Retorne SOMENTE JSON valido sem markdown, no formato:
{
  "status": "SIM|PARCIAL|NAO|SEM_EVIDENCIA",
  "diagnostico": "string",
  "impact_payload": {
    "problema": "string",
    "mudanca": "string",
    "evidencias": "string",
    "restricoes": "string"
  },
  "evidencias": [
    { "repo": "string", "pr_number": number, "url": "string", "arquivos": ["string"], "commits": ["string"] }
  ]
}

Regras:
1) impact_payload deve ser preenchido para acionar Impact Analysis.
2) Se faltar evidencia, use status=SEM_EVIDENCIA e descreva lacunas em diagnostico.
3) Nao invente PRs/arquivos/commits.

